import React from 'react';
import { ErrorMessage, useField, Field, useFormikContext } from 'formik';
import { useTranslation } from 'react-i18next';
import "./KarimField.scss";
import { FaExclamationCircle } from 'react-icons/fa';

type KarimFieldProps = {
  name: string;
  type: string;
  className?: string;
};

const KarimField: React.FC<KarimFieldProps> = ({ name, type, className = "" }) => {
  const { t } = useTranslation();
  const [field, meta] = useField(name);
  const formik = useFormikContext<a>();

  const isError = meta.touched && !!meta.error;
  const hasValue = !!field.value; 
  const inputClass = className + (isError ? " is-invalid" : hasValue ? " hasValue" : "");

  return (
    <div className={type === "checkbox" ? "KarimCheckbox" : "KarimField"}>
      <label htmlFor={field.name} className="text">
        {isError && <span className="isErrorIcon"><FaExclamationCircle /></span>}
        {name}
        <ErrorMessage name={field.name}>
          {msg => (
            <span className="field-error text-danger isErrorIcon">
              {t(msg)} <FaExclamationCircle />
            </span>
          )}
        </ErrorMessage>
      </label>

      {type === "checkbox" ? (
        <label className="cont">
          <input
            checked={formik.values[name] === 1}
            type="checkbox"
            name={name}
            onChange={() =>
              formik.setFieldValue(name, formik.values[name] === 1 ? 0 : 1)
            }
          />
          <span />
          {name}
        </label>
      ) : (
        <Field
          type={type}
          placeholder="Write Here..."
          name={field.name}
          className={inputClass}
        />
      )}
    </div>
  );
};

export default KarimField;
